"use strict";

const fs = require("fs");
const path = require("path");

const { extractRows } = require("./extract-perf-baseline.js");
const {
  SCENARIO_ORDER,
  DISPATCH_DISPLAY_NAMES,
  COMPARISON_SCENARIO_ORDER,
  COMPARISON_SCENARIO_LABELS,
  COMPARISON_TECH_ORDER,
  COMPARISON_TECH_LABELS,
  isComparisonScenario,
  parseComparisonScenario,
  deriveScope
} = require("./perf-scenarios.js");

// The auto-generated dispatch-throughput region lives between these two HTML
// comment markers in docs/architecture/performance.md. Humans must not edit
// inside the markers -- render-perf-doc.js owns that region and CI rewrites it
// from the latest Unity version's benchmark run. The region now holds a
// provenance line, one DISPATCH table per execution scope present, and (when
// comparison rows exist) three cross-library COMPARISON matrices.
const BEGIN_MARKER = "<!-- AUTOGENERATED:DISPATCH-THROUGHPUT BEGIN -->";
const END_MARKER = "<!-- AUTOGENERATED:DISPATCH-THROUGHPUT END -->";

// Wall-clock (latency) scenarios report wall-clock milliseconds, not emits/sec. This
// covers both registration floods (cold + warm-JIT), both deregistration floods (cold +
// warm-JIT), and the three cold first-dispatch scenarios. All carry emitsPerSecond=0 in
// the CSV; the renderer shows their wallClockMs.
const REGISTRATION_SCENARIOS = new Set([
  "RegistrationFlood_1000Types_FromColdBus",
  "RegistrationFlood_1000Types_WarmJit",
  "DeregistrationFlood_1000Types_Cold",
  "DeregistrationFlood_1000Types_WarmJit",
  "UntargetedFirstDispatch_Cold",
  "TargetedFirstDispatch_Cold",
  "BroadcastFirstDispatch_Cold"
]);

// Execution scopes in HEADLINE order: Standalone runs the IL2CPP/AOT backend in
// a Release player -- the configuration shipped games actually run -- so it is
// the headline scope and drives the comparison THROUGHPUT matrix and the
// provenance commit. In-editor PlayMode (Mono) and EditMode follow when present;
// CI now publishes BOTH the Standalone leg (throughput) AND the in-editor
// PlayMode leg (real GC allocations -- the Release player strips the profiler).
// The renderer stays scope-agnostic so adding/removing a leg is a workflow-only
// change. Dispatch tables render one section per scope PRESENT in this order; the
// comparison THROUGHPUT matrix uses the first scope present (Standalone when
// available) while the comparison GC-ALLOCATION matrix uses the first scope that
// actually MEASURED allocations (see preferredComparisonAllocScope).
const SCOPE_ORDER = ["Standalone", "PlayMode", "EditMode"];

// Each execution scope USUALLY runs a specific scripting backend: PlayMode and
// EditMode run under Mono (the shipped editor/runtime backend), while a Standalone
// player build runs under IL2CPP (AOT). This map is only the FALLBACK now -- the
// section label prefers the backend token actually present in the scope's platform
// rows (see deriveBackendLabel), so flipping the workflow's standalone backend back
// to Mono would make the heading follow the data instead of contradicting the
// Platform: line beneath it. Unknown scopes with no usable platform token fall back
// to "(Mono)".
const SCOPE_BACKEND = { Standalone: "IL2CPP", PlayMode: "Mono", EditMode: "Mono" };

// Idempotence tolerance. A new run whose every metric is within this relative
// fraction of the committed value is treated as unchanged so routine
// run-to-run jitter does not churn the doc / open no-op PRs.
const DEFAULT_TOLERANCE = 0.02;

// Neutral runner description used when no --machine-specs JSON is supplied (or it
// is missing / unparseable). The whole point of the machine-specs probe is to
// REPLACE a runner name/hostname with hardware specs, so this fallback must never
// leak a host identity -- it is a fixed, generic literal.
const NEUTRAL_RUNNER_DESCRIPTION = "self-hosted Windows runner";

function usage() {
  return `Usage: node scripts/unity/render-perf-doc.js --input <unity-log-or-results> [--input <path> ...] --doc <performance.md> --unity-version <version> [--platform-substring <s>] [--tolerance <fraction>] [--machine-specs <json>] [--check]

Extracts dispatch-throughput and library-comparison rows for a single Unity
version, renders deterministic per-scope tables plus cross-library comparison
matrices, and rewrites the AUTOGENERATED region of the performance doc in place.

  --input             Unity log or NUnit results file (repeatable).
  --doc               Target markdown file containing the AUTOGENERATED markers.
  --unity-version     Unity version whose rows drive the tables (e.g. 6000.3.16f1).
  --platform-substring Override the platform filter (default: "Unity <version>").
  --tolerance         Relative jitter tolerance for idempotence (default ${DEFAULT_TOLERANCE}).
  --machine-specs     Optional collect-machine-specs.ps1 JSON; embeds a Runner
                      provenance line (falls back to a neutral literal if absent).
  --check             Do not write; exit 3 if the doc would change. Useful in CI drift checks.

When the rendered region matches the existing region (within tolerance for
numeric cells), the file is left byte-for-byte unchanged and the process exits 0.
`;
}

function parseArgs(argv) {
  const options = {
    inputs: [],
    doc: "",
    unityVersion: "",
    platformSubstring: "",
    tolerance: DEFAULT_TOLERANCE,
    machineSpecs: "",
    check: false,
    help: false
  };

  for (let index = 2; index < argv.length; index++) {
    const arg = argv[index];
    if (arg === "--input") {
      options.inputs.push(requireValue(argv, ++index, arg));
      continue;
    }
    if (arg === "--doc") {
      options.doc = requireValue(argv, ++index, arg);
      continue;
    }
    if (arg === "--unity-version") {
      options.unityVersion = requireValue(argv, ++index, arg);
      continue;
    }
    if (arg === "--platform-substring") {
      options.platformSubstring = requireValue(argv, ++index, arg);
      continue;
    }
    if (arg === "--tolerance") {
      options.tolerance = parseTolerance(requireValue(argv, ++index, arg));
      continue;
    }
    if (arg === "--machine-specs") {
      options.machineSpecs = requireValue(argv, ++index, arg);
      continue;
    }
    if (arg === "--check") {
      options.check = true;
      continue;
    }
    if (arg === "--help" || arg === "-h") {
      options.help = true;
      continue;
    }
    throw new Error(`Unknown argument: ${arg}`);
  }

  return options;
}

function requireValue(argv, index, flag) {
  const value = argv[index];
  if (value === undefined || value.startsWith("--")) {
    throw new Error(`${flag} requires a value.`);
  }
  return value;
}

function parseTolerance(value) {
  const parsed = Number.parseFloat(value);
  if (!Number.isFinite(parsed) || parsed < 0) {
    throw new Error(`--tolerance must be a non-negative number, got: ${value}`);
  }
  return parsed;
}

function readInputs(inputs) {
  if (inputs.length === 0) {
    throw new Error("At least one --input path is required.");
  }
  return inputs
    .map((inputPath) => {
      if (!fs.existsSync(inputPath)) {
        throw new Error(`Input file not found: ${inputPath}`);
      }
      return fs.readFileSync(inputPath, "utf8");
    })
    .join("\n");
}

// deriveScope (platform -> Standalone/PlayMode/EditMode, else null) is the
// canonical copy in perf-scenarios.js (the shared, dependency-free module, so no
// circular require) and re-exported below for render-perf-deltas.js and the tests.

// Group the rows that match the requested Unity version into the structure the
// renderer needs:
//   - dispatchByScope:   Map<scope, Map<scenario, row>> (first row per scenario
//                        within a scope wins, deterministically).
//   - comparisonByScope: Map<scope, Map<"tech|scenario", row>> (first wins).
//   - scopesPresent:     ordered (headline-first) list of scopes with any
//                        dispatch rows.
// This replaces the old single-table "prefer Editor" selection: scopes are kept
// SEPARATE (one dispatch table each) and the comparison matrices later prefer the
// headline scope (first SCOPE_ORDER entry present; Standalone IL2CPP when
// available). Filtering to the version is by platform substring,
// exactly as before.
function selectRowsForVersion(rows, platformSubstring) {
  const matching = rows.filter((row) => row.platform.includes(platformSubstring));

  const dispatchByScope = new Map();
  const comparisonByScope = new Map();

  for (const row of matching) {
    const scope = deriveScope(row.platform);
    if (!scope) {
      continue;
    }

    if (isComparisonScenario(row.scenario)) {
      const parsed = parseComparisonScenario(row.scenario);
      if (!parsed) {
        continue;
      }
      if (!comparisonByScope.has(scope)) {
        comparisonByScope.set(scope, new Map());
      }
      const byCell = comparisonByScope.get(scope);
      const cellKey = `${parsed.techKey}|${parsed.scenarioKey}`;
      if (!byCell.has(cellKey)) {
        byCell.set(cellKey, row);
      }
      continue;
    }

    if (!SCENARIO_ORDER.includes(row.scenario)) {
      continue;
    }
    if (!dispatchByScope.has(scope)) {
      dispatchByScope.set(scope, new Map());
    }
    const byScenario = dispatchByScope.get(scope);
    if (!byScenario.has(row.scenario)) {
      byScenario.set(row.scenario, row);
    }
  }

  const scopesPresent = SCOPE_ORDER.filter((scope) => dispatchByScope.has(scope));

  return { dispatchByScope, comparisonByScope, scopesPresent };
}

function formatThroughput(emitsPerSecond) {
  const millions = Number.parseFloat(emitsPerSecond) / 1_000_000;
  return `${millions.toFixed(2)} M emits/sec`;
}

function formatWallClock(wallClockMs) {
  return `${Number.parseFloat(wallClockMs).toFixed(3)} ms`;
}

// Allocation is a COUNT of managed GC allocations over one measurement batch
// (AllocationProbe via the GC.Alloc recorder; smaller is better). -1 is the
// "Unmeasured" sentinel (no reliable probe on that backend) and renders "n/a",
// never "0"; a measured 0 is a real zero-alloc result. (Replaces the byte counter
// whose GC.GetAllocatedBytesForCurrentThread() source returns 0 for EVERY
// allocation under Unity's Boehm GC -- the old "Allocated bytes" column was vacuous.)
function formatAllocations(gcAllocations) {
  const count = Number.parseInt(gcAllocations, 10);
  if (!Number.isFinite(count) || count < 0) {
    return "n/a";
  }
  return count.toLocaleString("en-US");
}

// Allocated BYTES over one measurement batch (informational companion to the
// allocation count; smaller is better). -1 is the same "Unmeasured" sentinel and
// renders "n/a", never "0"; a measured 0 is a real zero-byte result.
function formatBytesAllocated(gcAllocatedBytes) {
  const bytes = Number.parseInt(gcAllocatedBytes, 10);
  if (!Number.isFinite(bytes) || bytes < 0) {
    return "n/a";
  }
  return bytes.toLocaleString("en-US");
}

// Comparison matrices show the same raw count (every tech runs the same BatchSize,
// so the counts are directly comparable; no per-op division).
function formatRowAllocations(row) {
  return formatAllocations(row.gcAllocations);
}

// Byte companion to formatRowAllocations for the GC-allocated-bytes matrix (same
// BatchSize across techs, so totals compare directly). Bytes show MAGNITUDE; the
// allocation count stays the canonical zero-alloc signal.
function formatRowBytes(row) {
  return formatBytesAllocated(row.gcAllocatedBytes);
}

// Read + parse the collect-machine-specs.ps1 JSON and format the one-line
// "Runner: ..." provenance string. Resilient by contract: a missing path, a
// missing/unreadable file, malformed JSON, or a non-object payload ALL fall back
// to the neutral literal rather than throwing -- the doc must render even when the
// runner failed to emit specs. Returns NEUTRAL_RUNNER_DESCRIPTION when machineSpecsPath
// is empty/undefined. Individual missing fields render as "unknown" (the .ps1
// already emits "unknown" for failed probes; this also guards a partial payload).
function readMachineSpecs(machineSpecsPath) {
  if (!machineSpecsPath) {
    return NEUTRAL_RUNNER_DESCRIPTION;
  }
  let raw;
  try {
    raw = fs.readFileSync(machineSpecsPath, "utf8");
  } catch {
    return NEUTRAL_RUNNER_DESCRIPTION;
  }
  let specs;
  try {
    specs = JSON.parse(raw);
  } catch {
    return NEUTRAL_RUNNER_DESCRIPTION;
  }
  if (!specs || typeof specs !== "object") {
    return NEUTRAL_RUNNER_DESCRIPTION;
  }
  return formatMachineSpecs(specs);
}

// Format a parsed machine-specs object into the one-line provenance string:
//   "<cpu>, <pc>C/<lc>T @ <clock>MHz; <ramGb>GB <ramType>@<ramSpeed>; <gpu>; <os>"
// Each field defaults to "unknown" when absent/empty so a partial payload never
// produces "undefined". Pure (no I/O) so it is unit-testable.
function formatMachineSpecs(specs) {
  const field = (value) => {
    if (value === undefined || value === null) {
      return "unknown";
    }
    const text = String(value).trim();
    return text.length === 0 ? "unknown" : text;
  };
  const cpu = field(specs.cpu);
  const physicalCores = field(specs.physicalCores);
  const logicalCores = field(specs.logicalCores);
  const clockMhz = field(specs.clockMhz);
  const ramGb = field(specs.ramGb);
  const ramType = field(specs.ramType);
  const ramSpeedMhz = field(specs.ramSpeedMhz);
  const gpu = field(specs.gpu);
  const os = field(specs.os);
  return (
    `${cpu}, ${physicalCores}C/${logicalCores}T @ ${clockMhz}MHz; ` +
    `${ramGb}GB ${ramType}@${ramSpeedMhz}; ${gpu}; ${os}`
  );
}

// Render a GFM table whose pipes are column-aligned the SAME way Prettier
// aligns them (each column padded to max(3, widest cell), one space of
// padding on each side, the separator row filled with dashes to the column
// width). The benchmark cells are pure ASCII, so this reproduces Prettier's GFM
// output byte-for-byte. Emitting the aligned form here -- rather than a compact
// `| --- |` form -- is what makes the rendered doc pass the repo's REQUIRED
// `prettier --check` markdown gate and stay byte-stable run-to-run (the
// workflow's post-render `prettier --write` becomes a verified no-op on the
// table).
function alignTable(rows) {
  const columnCount = rows[0].length;
  const widths = new Array(columnCount).fill(3);
  for (const cells of rows) {
    for (let column = 0; column < columnCount; column++) {
      widths[column] = Math.max(widths[column], cells[column].length);
    }
  }

  const renderRow = (cells) =>
    `| ${cells.map((cell, column) => cell.padEnd(widths[column])).join(" | ")} |`;
  const separator = `| ${widths.map((width) => "-".repeat(width)).join(" | ")} |`;

  const [header, ...body] = rows;
  return [renderRow(header), separator, ...body.map(renderRow)].join("\n");
}

// Build one dispatch-throughput table for a single scope. Rows follow
// SCENARIO_ORDER; the Scenario cell shows the human DisplayName (NOT the raw
// key); registration scenarios show wall-clock, others throughput.
function buildDispatchTable(byScenario) {
  // "GC allocs" (no fixed denominator): throughput rows count over a 10k-op batch,
  // cold rows over one op per trial, registration floods over one flood -- each row's
  // count is over its own measurement batch, so a single "/ 10k ops" denominator
  // would overstate the cold/flood rows.
  const header = ["Scenario", "Throughput / Wall clock", "GC allocs", "GC bytes"];
  const dataRows = [];

  for (const scenario of SCENARIO_ORDER) {
    const row = byScenario.get(scenario);
    if (!row) {
      continue;
    }
    const primary = REGISTRATION_SCENARIOS.has(scenario)
      ? formatWallClock(row.wallClockMs)
      : formatThroughput(row.emitsPerSecond);
    const label = DISPATCH_DISPLAY_NAMES[scenario] || scenario;
    dataRows.push([
      label,
      primary,
      formatAllocations(row.gcAllocations),
      formatBytesAllocated(row.gcAllocatedBytes)
    ]);
  }

  return dataRows.length === 0 ? null : alignTable([header, ...dataRows]);
}

// Build the per-scope dispatch sections (label + Platform line + table) in
// headline scope order (SCOPE_ORDER; Standalone first). Returns an array of markdown line-arrays.
function buildDispatchSections(dispatchByScope, scopesPresent) {
  const sections = [];
  for (const scope of scopesPresent) {
    const byScenario = dispatchByScope.get(scope);
    const table = buildDispatchTable(byScenario);
    if (!table) {
      continue;
    }
    const sampleRow = SCENARIO_ORDER.map((scenario) => byScenario.get(scenario)).find(Boolean);
    const platform = sampleRow ? sampleRow.platform : "unknown";
    sections.push([
      // h3: the AUTOGENERATED region lives under the "## Latest CI dispatch
      // throughput" h2 in performance.md, so the first heading here must be h3
      // to satisfy markdownlint MD001 (heading-increment). Do not deepen to h4
      // without introducing an intervening h3 parent.
      `### Dispatch throughput - ${scopeLabel(scope, platform)}`,
      "",
      `Platform: ${platform}.`,
      "",
      table
    ]);
  }
  return sections;
}

// Choose the scope whose comparison rows feed the cross-library THROUGHPUT
// matrix: the first scope in SCOPE_ORDER (headline order) that actually has
// comparison rows -- Standalone when present, else PlayMode, else EditMode.
function preferredComparisonScope(comparisonByScope) {
  for (const scope of SCOPE_ORDER) {
    const byCell = comparisonByScope.get(scope);
    if (byCell && byCell.size > 0) {
      return scope;
    }
  }
  return null;
}

// Choose the scope whose comparison rows feed the cross-library GC-ALLOCATION
// matrix. Throughput stays on the HEADLINE scope (preferredComparisonScope), but
// allocations are only meaningful where the profiler actually measured them: a
// Release IL2CPP player strips the GC.Alloc recorder, so every Standalone alloc
// cell is the -1 "Unmeasured" sentinel (rendered "n/a"). Pick the first scope in
// headline order that has at least one MEASURED allocation (gcAllocations parses
// to an integer >= 0; -1 is the sentinel), so an in-editor Mono leg's real counts
// drive the alloc matrix when present. Fall back to preferredComparisonScope when
// NO scope measured allocations, preserving today's behavior (alloc matrix stays
// all n/a on the headline scope) when only a Release player ran.
function preferredComparisonAllocScope(comparisonByScope) {
  for (const scope of SCOPE_ORDER) {
    const byCell = comparisonByScope.get(scope);
    if (!byCell) {
      continue;
    }
    for (const row of byCell.values()) {
      const count = Number.parseInt(row.gcAllocations, 10);
      if (Number.isFinite(count) && count >= 0) {
        return scope;
      }
    }
  }
  return preferredComparisonScope(comparisonByScope);
}

// Render one cross-library comparison matrix's data rows for a single scope.
// Returns null when no tech has any comparison row in the scope (a fully-absent
// tech is omitted rather than rendered as an all-N/A row). `bold` is true only
// for the throughput matrix -- the fastest tech per scenario COLUMN is bolded so
// the per-category winner is visible at a glance (ties at DISPLAY precision are
// all bolded; N/A capability gaps never win). The allocations matrix is never
// bolded (the GC-allocation count is a property, not a race). `formatCell` turns
// a row into its cell text and cells absent for a (tech, scenario) show N/A.
function buildComparisonMatrix(byCell, formatCell, { bold }) {
  const techsPresent = COMPARISON_TECH_ORDER.filter((techKey) =>
    COMPARISON_SCENARIO_ORDER.some((scenarioKey) => byCell.has(`${techKey}|${scenarioKey}`))
  );
  if (techsPresent.length === 0) {
    return null;
  }

  const header = [
    "Technology",
    ...COMPARISON_SCENARIO_ORDER.map((key) => COMPARISON_SCENARIO_LABELS[key])
  ];

  // Winners are computed at DISPLAY precision (the formatted cell text): two
  // techs that render identically are visually tied, so both are bolded even
  // when their raw floats differ in digits the reader cannot see. This also
  // reduces bold flapping between near-tied techs across runs.
  const winningCellByScenario = new Map();
  if (bold) {
    for (const scenarioKey of COMPARISON_SCENARIO_ORDER) {
      let best = -Infinity;
      for (const techKey of techsPresent) {
        const row = byCell.get(`${techKey}|${scenarioKey}`);
        if (!row) {
          continue;
        }
        const emitsPerSecond = Number.parseFloat(row.emitsPerSecond);
        if (Number.isFinite(emitsPerSecond) && emitsPerSecond > best) {
          best = emitsPerSecond;
        }
      }
      if (best > 0) {
        winningCellByScenario.set(scenarioKey, formatThroughput(best));
      }
    }
  }

  const dataRows = [header];
  for (const techKey of techsPresent) {
    const cells = [COMPARISON_TECH_LABELS[techKey] || techKey];
    for (const scenarioKey of COMPARISON_SCENARIO_ORDER) {
      const row = byCell.get(`${techKey}|${scenarioKey}`);
      if (!row) {
        cells.push("N/A");
        continue;
      }
      const formatted = formatCell(row);
      const isWinner = bold && winningCellByScenario.get(scenarioKey) === formatted;
      cells.push(isWinner ? `**${formatted}**` : formatted);
    }
    dataRows.push(cells);
  }

  return alignTable(dataRows);
}

// Build the three cross-library comparison matrices. The THROUGHPUT matrix uses the
// HEADLINE scope (preferredComparisonScope; Standalone when present). The
// GC-ALLOCATION count matrix uses the scope that actually MEASURED allocations
// (preferredComparisonAllocScope; the in-editor Mono leg when present, since a
// Release IL2CPP player strips the profiler). The GC-ALLOCATED-BYTES matrix is the
// count matrix's byte-magnitude companion and SHARES its scope (one probe measures
// both metrics in the same leg). Each matrix is labeled with its own scope's backend.
// Returns an array of markdown line-arrays, or [] when there are no comparison rows.
// With only the Standalone scope present, all three resolve to Standalone and the
// output matches the single-scope behavior.
function buildComparisonSections(comparisonByScope) {
  const throughputScope = preferredComparisonScope(comparisonByScope);
  if (!throughputScope) {
    return [];
  }
  const throughputByCell = comparisonByScope.get(throughputScope);
  const throughputSample = throughputByCell.values().next().value;
  const throughputPlatform = throughputSample ? throughputSample.platform : undefined;
  const throughputTable = buildComparisonMatrix(
    throughputByCell,
    (row) => formatThroughput(row.emitsPerSecond),
    { bold: true }
  );
  if (!throughputTable) {
    return [];
  }

  let allocScope = preferredComparisonAllocScope(comparisonByScope);
  let allocByCell = comparisonByScope.get(allocScope);
  let allocTable = buildComparisonMatrix(allocByCell, formatRowAllocations, { bold: false });
  // Symmetry with the throughput guard above: if the alloc scope somehow yields
  // no techs (an empty matrix), fall back to the throughput scope's cells -- which
  // we already proved render a non-null table -- so the alloc section never pushes
  // a null. This is defense-in-depth: every comparisonByScope cell key is a valid
  // tech|scenario pair, so a scope with any row always has >= 1 tech, and the
  // alloc scope (a measured-alloc scope, else the throughput scope) always has
  // rows -- so this fallback is currently unreachable but keeps the throughput/alloc matrices'
  // null handling identical (the bytes matrix reuses the proven-non-null allocByCell).
  if (!allocTable) {
    allocScope = throughputScope;
    allocByCell = throughputByCell;
    allocTable = buildComparisonMatrix(allocByCell, formatRowAllocations, { bold: false });
  }
  const allocSample = allocByCell.values().next().value;
  const allocPlatform = allocSample ? allocSample.platform : undefined;

  // The bytes matrix is the byte-magnitude companion to the COUNT matrix and SHARES
  // its scope: one probe measures count and bytes in the same leg (a Release player
  // strips both; the editor Mono leg measures both). allocByCell already rendered a
  // non-null table above; cells without a measured byte total render n/a.
  const bytesTable = buildComparisonMatrix(allocByCell, formatRowBytes, { bold: false });

  return [
    [
      // h3 siblings of the dispatch-throughput section (see its comment): the
      // region's parent is an h2, so every top-level region heading is h3.
      `### Library comparison - throughput (${scopeLabel(throughputScope, throughputPlatform)})`,
      "",
      throughputTable
    ],
    [
      `### Library comparison - GC allocations per 10k ops (${scopeLabel(allocScope, allocPlatform)})`,
      "",
      allocTable
    ],
    [
      `### Library comparison - GC allocated bytes per 10k ops (${scopeLabel(allocScope, allocPlatform)})`,
      "",
      bytesTable
    ]
  ];
}

// Derive the scripting backend from a scope's actual platform string token. The
// benchmark already emits the backend in the platform (e.g.
// "Standalone IL2CPP x64 ..." / "Editor PlayMode Mono x64 ..."), so the heading
// follows the DATA rather than a hard-coded scope->backend assumption: an IL2CPP
// token wins, else a Mono token, else null (no usable token -> caller falls back to
// the SCOPE_BACKEND map). This keeps the heading consistent with the Platform: line
// even if the workflow ever flips a scope's backend (e.g. Standalone back to Mono).
function deriveBackendLabel(platform) {
  if (typeof platform === "string") {
    if (/\bIL2CPP\b/i.test(platform)) {
      return "IL2CPP";
    }
    if (/\bMono\b/i.test(platform)) {
      return "Mono";
    }
  }
  return null;
}

// Surface the per-scope scripting backend next to the scope so the section labels
// read e.g. "PlayMode (Mono)" / "Standalone (IL2CPP)". The backend is DERIVED from
// the scope's actual platform string token when one is supplied (deriveBackendLabel);
// otherwise it falls back to the SCOPE_BACKEND map, and finally to "Mono" for an
// unknown scope.
function scopeLabel(scope, platform) {
  const backend = deriveBackendLabel(platform) || SCOPE_BACKEND[scope] || "Mono";
  return `${scope} (${backend})`;
}

// The rendered block carries a provenance line (which Unity version / commit
// produced it), an optional Runner hardware line, the per-scope dispatch tables,
// then the cross-library comparison matrices, framed by the AUTOGENERATED markers.
// The commit is read from the first selected row (headline scope order, then
// SCENARIO_ORDER) so the doc is traceable to a real run. The optional
// `runnerDescription` is rendered as a NON-table provenance line so the
// idempotence row-comparator (blocksEquivalent) ignores it -- a runner-spec or
// commit change never opens a churn PR on its own.
function buildBlock(selection, unityVersion, { runnerDescription = "" } = {}) {
  const { dispatchByScope, comparisonByScope, scopesPresent } = selection;

  const dispatchSections = buildDispatchSections(dispatchByScope, scopesPresent);
  if (dispatchSections.length === 0) {
    throw new Error(
      `No DispatchThroughputBenchmarks rows matched Unity ${unityVersion}. ` +
        "Check the --unity-version / --platform-substring filter and the input logs."
    );
  }
  const comparisonSections = buildComparisonSections(comparisonByScope);

  const commit = firstSelectedCommit(selection);

  const lines = [
    BEGIN_MARKER,
    "",
    "<!-- Do not edit by hand. Rewritten by scripts/unity/render-perf-doc.js from",
    "     the latest Unity version's benchmark run. See perf-numbers.yml. -->",
    "",
    `Latest CI benchmark run: Unity ${unityVersion}, commit \`${commit}\`.`
  ];

  if (runnerDescription) {
    lines.push("");
    lines.push(`Runner: ${runnerDescription}`);
  }

  for (const section of [...dispatchSections, ...comparisonSections]) {
    lines.push("");
    lines.push(...section);
  }

  lines.push("");
  lines.push(END_MARKER);
  return lines.join("\n");
}

// The provenance commit comes from the first dispatch row in headline scope
// order (SCOPE_ORDER; Standalone first), then SCENARIO_ORDER, so it is
// deterministic and tied to a real run.
function firstSelectedCommit(selection) {
  for (const scope of selection.scopesPresent) {
    const byScenario = selection.dispatchByScope.get(scope);
    for (const scenario of SCENARIO_ORDER) {
      const row = byScenario.get(scenario);
      if (row) {
        return row.commit;
      }
    }
  }
  return "unknown";
}

function countOccurrences(content, needle) {
  let count = 0;
  let from = 0;
  for (;;) {
    const at = content.indexOf(needle, from);
    if (at === -1) {
      return count;
    }
    count += 1;
    from = at + needle.length;
  }
}

function locateMarkers(content) {
  const beginIndex = content.indexOf(BEGIN_MARKER);
  const endIndex = content.indexOf(END_MARKER);
  if (beginIndex === -1 || endIndex === -1) {
    throw new Error(
      `Could not find AUTOGENERATED dispatch-throughput markers in the doc. ` +
        `Expected both '${BEGIN_MARKER}' and '${END_MARKER}'.`
    );
  }
  // LOW-1: a second BEGIN/END pair would make the first-match slicing below
  // rewrite only the first region and silently leave a stale duplicate behind.
  // Refuse to guess -- require exactly one of each marker.
  const beginCount = countOccurrences(content, BEGIN_MARKER);
  const endCount = countOccurrences(content, END_MARKER);
  if (beginCount !== 1 || endCount !== 1) {
    throw new Error(
      `Expected exactly one AUTOGENERATED dispatch-throughput marker pair, ` +
        `found ${beginCount} '${BEGIN_MARKER}' and ${endCount} '${END_MARKER}'. ` +
        "Remove the duplicate markers so the renderer owns a single region."
    );
  }
  if (endIndex < beginIndex) {
    throw new Error("AUTOGENERATED END marker appears before BEGIN marker in the doc.");
  }
  return { beginIndex, endIndex: endIndex + END_MARKER.length };
}

function replaceBlock(content, block) {
  const { beginIndex, endIndex } = locateMarkers(content);
  return content.slice(0, beginIndex) + block + content.slice(endIndex);
}

// Pull the numeric value out of a rendered metric cell so two cells can be
// compared with a jitter tolerance instead of byte equality. Non-numeric cells
// (scenario names, units, "N/A") compare exactly via the surrounding text.
function extractCellNumbers(text) {
  const matches = text.match(/-?\d[\d,]*(?:\.\d+)?/g);
  if (!matches) {
    return [];
  }
  return matches.map((token) => Number.parseFloat(token.replace(/,/g, "")));
}

function stripNumbers(text) {
  return text.replace(/-?\d[\d,]*(?:\.\d+)?/g, "#");
}

// CRITICAL-2: equivalence is decided ONLY on the markdown TABLE ROWS inside the
// block, never on the surrounding lines.
//
//   (a) The provenance line ("Latest CI benchmark run: Unity <v>, commit
//       `<sha>`"), the per-scope label/Platform lines, and the matrix headings
//       live inside the markers but are NOT table rows, so a changed commit hash
//       -- which moves every run as master advances -- no longer makes the block
//       "differ" and no longer triggers a churn rewrite.
//
//   (b) Each table row is compared cell-by-cell on its TRIMMED cells, so the
//       comparison is insensitive to Prettier's column alignment.
//
// Row order is deterministic (fixed scope order, SCENARIO_ORDER, tech order,
// comparison-scenario column order), so re-rendering equivalent numbers compares
// row-for-row. "N/A" cells contain no digits -> extractCellNumbers returns [] ->
// they compare by skeleton text. A row's non-numeric skeleton must match exactly
// and every numeric cell must be within `tolerance` (relative). That is what
// keeps the update idempotent across the multiple tables/matrices.
function tableRowCells(line) {
  const trimmed = line.trim();
  if (!trimmed.startsWith("|")) {
    return null;
  }
  return (
    trimmed
      .replace(/^\|/, "")
      .replace(/\|$/, "")
      .split("|")
      // Winner-bold markers (**cell**) are presentation, not data: normalize them
      // away so a within-tolerance jitter that merely moves the bold between two
      // near-tied techs does not defeat the idempotence comparison and churn the
      // committed doc. Numbers inside the markers still tolerance-compare.
      .map((cell) => cell.trim().replace(/^\*\*(.*)\*\*$/, "$1"))
  );
}

function isSeparatorCells(cells) {
  return cells.every((cell) => /^:?-+:?$/.test(cell));
}

function tableRows(block) {
  return block
    .split(/\r?\n/)
    .map(tableRowCells)
    .filter((cells) => cells !== null);
}

function rowsEquivalent(existingCells, candidateCells, tolerance) {
  if (existingCells.length !== candidateCells.length) {
    return false;
  }
  // Separator rows differ only in dash count once Prettier aligns the table;
  // treat any two well-formed separator rows of equal arity as equal.
  if (isSeparatorCells(existingCells) && isSeparatorCells(candidateCells)) {
    return true;
  }
  for (let column = 0; column < existingCells.length; column++) {
    const existingCell = existingCells[column];
    const candidateCell = candidateCells[column];
    if (stripNumbers(existingCell) !== stripNumbers(candidateCell)) {
      return false;
    }
    const existingNumbers = extractCellNumbers(existingCell);
    const candidateNumbers = extractCellNumbers(candidateCell);
    if (existingNumbers.length !== candidateNumbers.length) {
      return false;
    }
    for (let n = 0; n < existingNumbers.length; n++) {
      if (!withinTolerance(existingNumbers[n], candidateNumbers[n], tolerance)) {
        return false;
      }
    }
  }
  return true;
}

function blocksEquivalent(existingBlock, candidateBlock, tolerance) {
  const existingRows = tableRows(existingBlock);
  const candidateRows = tableRows(candidateBlock);
  if (existingRows.length === 0 || existingRows.length !== candidateRows.length) {
    return false;
  }
  for (let index = 0; index < existingRows.length; index++) {
    if (!rowsEquivalent(existingRows[index], candidateRows[index], tolerance)) {
      return false;
    }
  }
  return true;
}

function withinTolerance(existing, candidate, tolerance) {
  if (existing === candidate) {
    return true;
  }
  const denominator = Math.max(Math.abs(existing), Math.abs(candidate));
  if (denominator === 0) {
    return true;
  }
  return Math.abs(existing - candidate) / denominator <= tolerance;
}

function extractExistingBlock(content) {
  const { beginIndex, endIndex } = locateMarkers(content);
  return content.slice(beginIndex, endIndex);
}

function render(options) {
  const rows = extractRows(readInputs(options.inputs));
  if (rows.length === 0) {
    throw new Error("No DispatchThroughputBenchmarks rows found in the inputs.");
  }

  const platformSubstring =
    options.platformSubstring || `Unity ${requireUnityVersion(options.unityVersion)}`;
  const selection = selectRowsForVersion(rows, platformSubstring);
  const runnerDescription = readMachineSpecs(options.machineSpecs);
  const candidateBlock = buildBlock(selection, options.unityVersion, { runnerDescription });

  const originalContent = fs.readFileSync(options.doc, "utf8");
  const existingBlock = extractExistingBlock(originalContent);

  if (blocksEquivalent(existingBlock, candidateBlock, options.tolerance)) {
    return { changed: false, content: originalContent };
  }

  const updatedContent = replaceBlock(originalContent, candidateBlock);
  return { changed: true, content: updatedContent };
}

function requireUnityVersion(value) {
  if (!value) {
    throw new Error("--unity-version is required (or pass --platform-substring explicitly).");
  }
  return value;
}

function main(argv = process.argv) {
  const options = parseArgs(argv);
  if (options.help) {
    process.stdout.write(usage());
    return 0;
  }
  if (!options.doc) {
    throw new Error("--doc is required.");
  }
  if (!fs.existsSync(options.doc)) {
    throw new Error(`Doc file not found: ${options.doc}`);
  }

  const result = render(options);

  if (options.check) {
    if (result.changed) {
      process.stderr.write(
        `Performance doc is out of date: ${path.relative(process.cwd(), options.doc)} ` +
          "would change. Re-run render-perf-doc.js without --check (or wait for the " +
          "perf-numbers.yml default-branch refresh run) to refresh it.\n"
      );
      return 3;
    }
    process.stderr.write("Performance doc is up to date.\n");
    return 0;
  }

  if (!result.changed) {
    process.stderr.write("Performance doc already up to date; no write performed.\n");
    return 0;
  }

  fs.writeFileSync(options.doc, result.content, "utf8");
  process.stderr.write(`Updated dispatch-throughput tables in ${options.doc}.\n`);
  return 0;
}

if (require.main === module) {
  try {
    process.exitCode = main();
  } catch (error) {
    process.stderr.write(`${error.message}\n\n${usage()}`);
    process.exitCode = 1;
  }
}

// Export pure helpers consumed by render-perf-deltas.js and the node:test suite.
// Keep I/O-heavy entry points behind main()/render() instead of exporting them.
module.exports = {
  deriveScope,
  alignTable,
  buildComparisonSections,
  buildDispatchSections,
  buildBlock,
  selectRowsForVersion,
  blocksEquivalent
};
